"""sklearn.manifold — Manifold learning (dimensionality reduction)."""
import numpy as np
from sklearn.base import BaseEstimator, TransformerMixin


def _pairwise_distances(X, Y=None):
    if Y is None:
        Y = X
    sq = np.sum(X ** 2, axis=1, keepdims=True) + np.sum(Y ** 2, axis=1) - 2 * X @ Y.T
    return np.sqrt(np.maximum(sq, 0))


class TSNE(BaseEstimator, TransformerMixin):
    """t-distributed Stochastic Neighbour Embedding (simplified).

    Parameters
    ----------
    n_components : int, default=2
    perplexity : float, default=30.0
    learning_rate : float, default=200.0
    n_iter : int, default=300
    random_state : int or None, default=None
    """

    def __init__(self, n_components=2, *, perplexity=30.0, early_exaggeration=12.0,
                 learning_rate='auto', n_iter=300, max_iter=None,
                 n_iter_without_progress=300, min_grad_norm=1e-7,
                 metric='euclidean', metric_params=None, init='pca',
                 verbose=0, random_state=None, method='barnes_hut',
                 angle=0.5, n_jobs=None):
        self.n_components = n_components
        self.perplexity = perplexity
        self.early_exaggeration = early_exaggeration
        self.learning_rate = 200.0 if learning_rate == 'auto' else learning_rate
        self.n_iter = max_iter if max_iter is not None else n_iter
        self.max_iter = self.n_iter
        self.n_iter_without_progress = n_iter_without_progress
        self.min_grad_norm = min_grad_norm
        self.metric = metric
        self.metric_params = metric_params
        self.init = init
        self.verbose = verbose
        self.random_state = random_state
        self.method = method
        self.angle = angle
        self.n_jobs = n_jobs

    def fit_transform(self, X, y=None):
        rng = np.random.RandomState(self.random_state)
        X = np.asarray(X, dtype=float)
        n = X.shape[0]

        # Compute pairwise affinities
        D = _pairwise_distances(X)
        P = np.zeros((n, n))
        target_entropy = np.log(self.perplexity)

        for i in range(n):
            lo, hi = 1e-10, 1e4
            for _ in range(50):
                sigma = (lo + hi) / 2
                pi = np.exp(-D[i] ** 2 / (2 * sigma ** 2))
                pi[i] = 0
                s = pi.sum()
                if s == 0:
                    lo = sigma
                    continue
                pi /= s
                entropy = -np.sum(pi[pi > 0] * np.log(pi[pi > 0]))
                if entropy > target_entropy:
                    hi = sigma
                else:
                    lo = sigma
            P[i] = pi

        P = (P + P.T) / (2 * n)
        P = np.maximum(P, 1e-12)

        # Init
        Y = rng.randn(n, self.n_components) * 0.01
        velocity = np.zeros_like(Y)
        momentum = 0.5

        for it in range(self.n_iter):
            if it == 100:
                momentum = 0.8

            # Compute Q
            d = _pairwise_distances(Y)
            Q = 1.0 / (1.0 + d ** 2)
            np.fill_diagonal(Q, 0)
            Q_sum = Q.sum()
            Q_norm = Q / max(Q_sum, 1e-15)
            Q_norm = np.maximum(Q_norm, 1e-12)

            # Gradient
            PQ = P - Q_norm
            grad = np.zeros_like(Y)
            for i in range(n):
                diff = Y[i] - Y
                grad[i] = 4 * np.sum((PQ[i] * Q[i])[:, None] * diff, axis=0)

            velocity = momentum * velocity - self.learning_rate * grad
            Y += velocity

        self.embedding_ = Y
        return Y

    def fit(self, X, y=None):
        self.fit_transform(X, y)
        return self

    def transform(self, X):
        return self.embedding_


class MDS(BaseEstimator, TransformerMixin):
    """Multidimensional Scaling (classical / metric).

    Parameters
    ----------
    n_components : int, default=2
    random_state : int or None, default=None
    """

    def __init__(self, n_components=2, *, metric=True, n_init=4, max_iter=300,
                 verbose=0, eps=1e-3, n_jobs=None, random_state=None,
                 dissimilarity='euclidean', normalized_stress='auto'):
        self.n_components = n_components
        self.metric = metric
        self.n_init = n_init
        self.max_iter = max_iter
        self.verbose = verbose
        self.eps = eps
        self.n_jobs = n_jobs
        self.dissimilarity = dissimilarity
        self.normalized_stress = normalized_stress
        self.random_state = random_state

    def fit_transform(self, X, y=None):
        X = np.asarray(X, dtype=float)
        D = _pairwise_distances(X)
        D2 = D ** 2
        n = D.shape[0]
        H = np.eye(n) - np.ones((n, n)) / n
        B = -0.5 * H @ D2 @ H
        eig_vals, eig_vecs = np.linalg.eigh(B)
        idx = np.argsort(eig_vals)[::-1][:self.n_components]
        L = np.maximum(eig_vals[idx], 0)
        self.embedding_ = eig_vecs[:, idx] * np.sqrt(L)
        return self.embedding_

    def fit(self, X, y=None):
        self.fit_transform(X, y)
        return self

    def transform(self, X):
        return self.embedding_


class Isomap(BaseEstimator, TransformerMixin):
    """Isomap embedding (geodesic MDS).

    Parameters
    ----------
    n_components : int, default=2
    n_neighbors : int, default=5
    """

    def __init__(self, n_components=2, *, n_neighbors=5, eigen_solver='auto',
                 tol=0, max_iter=None, path_method='auto',
                 neighbors_algorithm='auto', n_jobs=None, metric='minkowski',
                 p=2, metric_params=None):
        self.n_components = n_components
        self.eigen_solver = eigen_solver
        self.tol = tol
        self.max_iter = max_iter
        self.path_method = path_method
        self.neighbors_algorithm = neighbors_algorithm
        self.n_jobs = n_jobs
        self.metric = metric
        self.p = p
        self.metric_params = metric_params
        self.n_neighbors = n_neighbors

    def fit_transform(self, X, y=None):
        X = np.asarray(X, dtype=float)
        n = X.shape[0]
        D = _pairwise_distances(X)

        # Build kNN graph
        G = np.full((n, n), np.inf)
        np.fill_diagonal(G, 0)
        for i in range(n):
            nn = np.argsort(D[i])[:self.n_neighbors + 1]
            for j in nn:
                G[i, j] = D[i, j]
                G[j, i] = D[j, i]

        # Floyd-Warshall shortest paths
        for k in range(n):
            for i in range(n):
                for j in range(n):
                    if G[i, k] + G[k, j] < G[i, j]:
                        G[i, j] = G[i, k] + G[k, j]

        # Classical MDS on geodesic distances
        G[G == np.inf] = G[G < np.inf].max() * 2
        D2 = G ** 2
        H = np.eye(n) - np.ones((n, n)) / n
        B = -0.5 * H @ D2 @ H
        eig_vals, eig_vecs = np.linalg.eigh(B)
        idx = np.argsort(eig_vals)[::-1][:self.n_components]
        L = np.maximum(eig_vals[idx], 0)
        self.embedding_ = eig_vecs[:, idx] * np.sqrt(L)
        return self.embedding_

    def fit(self, X, y=None):
        self.fit_transform(X, y)
        return self

    def transform(self, X):
        return self.embedding_


# ---------------------------------------------------------------------------
# Locally Linear Embedding
# ---------------------------------------------------------------------------

class LocallyLinearEmbedding(BaseEstimator, TransformerMixin):
    """Locally Linear Embedding (LLE).

    Find reconstruction weights from k-neighbors, then embed via
    eigenvectors of (I - W)^T (I - W).
    """

    def __init__(self, *, n_neighbors=5, n_components=2, reg=1e-3,
                 eigen_solver='auto', tol=1e-6, max_iter=100,
                 method='standard', hessian_tol=1e-4, modified_tol=1e-12,
                 neighbors_algorithm='auto', random_state=None, n_jobs=None):
        self.n_neighbors = n_neighbors
        self.n_components = n_components
        self.reg = reg
        self.eigen_solver = eigen_solver
        self.tol = tol
        self.max_iter = max_iter
        self.method = method
        self.hessian_tol = hessian_tol
        self.modified_tol = modified_tol
        self.neighbors_algorithm = neighbors_algorithm
        self.random_state = random_state
        self.n_jobs = n_jobs

    def fit_transform(self, X, y=None):
        X = np.asarray(X, dtype=float)
        n, d = X.shape
        k = min(self.n_neighbors, n - 1)

        # Step 1: Find k nearest neighbors
        D = _pairwise_distances(X)
        neighbors = np.zeros((n, k), dtype=int)
        for i in range(n):
            neighbors[i] = np.argsort(D[i])[1:k + 1]

        # Step 2: Compute reconstruction weights
        W = np.zeros((n, n))
        for i in range(n):
            nbrs = neighbors[i]
            Z = X[nbrs] - X[i]  # k x d
            C = Z @ Z.T  # k x k local covariance
            # Regularize
            C += self.reg * np.eye(k)
            try:
                w = np.linalg.solve(C, np.ones(k))
            except np.linalg.LinAlgError:
                w = np.ones(k)
            w /= max(w.sum(), 1e-10)
            W[i, nbrs] = w

        # Step 3: Compute embedding from eigenvectors of M = (I - W)^T (I - W)
        I_W = np.eye(n) - W
        M = I_W.T @ I_W

        eig_vals, eig_vecs = np.linalg.eigh(M)
        # Skip the first eigenvector (eigenvalue ~0 corresponds to constant)
        # Take the next n_components eigenvectors
        idx = np.argsort(eig_vals)[1:self.n_components + 1]
        self.embedding_ = eig_vecs[:, idx]
        self.reconstruction_error_ = float(eig_vals[idx].sum())
        return self.embedding_

    def fit(self, X, y=None):
        self.fit_transform(X, y)
        return self

    def transform(self, X):
        return self.embedding_


# ---------------------------------------------------------------------------
# Spectral Embedding
# ---------------------------------------------------------------------------

class SpectralEmbedding(BaseEstimator, TransformerMixin):
    """Spectral embedding using Laplacian eigenvectors."""

    def __init__(self, n_components=2, *, affinity='nearest_neighbors',
                 gamma=None, random_state=None, eigen_solver=None,
                 eigen_tol='auto', n_neighbors=None, n_jobs=None):
        self.n_components = n_components
        self.affinity = affinity
        self.gamma = gamma
        self.random_state = random_state
        self.eigen_solver = eigen_solver
        self.eigen_tol = eigen_tol
        self.n_neighbors = n_neighbors
        self.n_jobs = n_jobs

    def fit_transform(self, X, y=None):
        X = np.asarray(X, dtype=float)
        n = X.shape[0]
        D = _pairwise_distances(X)

        if self.affinity == 'nearest_neighbors':
            k = self.n_neighbors if self.n_neighbors is not None else min(10, n - 1)
            k = min(k, n - 1)
            # Build affinity matrix from k-nearest neighbors
            A = np.zeros((n, n))
            for i in range(n):
                nn = np.argsort(D[i])[1:k + 1]
                for j in nn:
                    A[i, j] = 1.0
                    A[j, i] = 1.0
            # Use heat kernel on the kNN graph
            gamma = self.gamma if self.gamma is not None else 1.0 / X.shape[1]
            W = A * np.exp(-gamma * D ** 2)
        elif self.affinity == 'rbf':
            gamma = self.gamma if self.gamma is not None else 1.0 / X.shape[1]
            W = np.exp(-gamma * D ** 2)
        else:
            # Default: rbf
            gamma = self.gamma if self.gamma is not None else 1.0 / X.shape[1]
            W = np.exp(-gamma * D ** 2)

        np.fill_diagonal(W, 0)

        # Compute normalized Laplacian eigenvectors
        degree = W.sum(axis=1)
        D_inv_sqrt = np.diag(1.0 / np.sqrt(np.maximum(degree, 1e-10)))
        L_norm = np.eye(n) - D_inv_sqrt @ W @ D_inv_sqrt

        eig_vals, eig_vecs = np.linalg.eigh(L_norm)
        # Take smallest non-trivial eigenvectors
        idx = np.argsort(eig_vals)[1:self.n_components + 1]
        self.embedding_ = eig_vecs[:, idx]
        self.affinity_matrix_ = W
        return self.embedding_

    def fit(self, X, y=None):
        self.fit_transform(X, y)
        return self

    def transform(self, X):
        return self.embedding_
